// MARK: - Log Level

enum LogLevel: Int, Comparable {
    case verbose = 0
    case debug = 1
    case info = 2
    case warning = 3
    case error = 4
    case critical = 5
    case none = 6
    
    static func < (lhs: LogLevel, rhs: LogLevel) -> Bool {
        return lhs.rawValue < rhs.rawValue
    }
    
    var prefix: String {
        switch self {
        case .verbose:  return "📝 [VERBOSE]"
        case .debug:    return "🔍 [DEBUG]"
        case .info:     return "ℹ️ [INFO]"
        case .warning:  return "⚠️ [WARNING]"
        case .error:    return "❌ [ERROR]"
        case .critical: return "🔥 [CRITICAL]"
        case .none:     return ""
        }
    }
}

// MARK: - Redaction Utilities

struct SensitiveDataRedactor {
    
    // Keys whose values should always be fully redacted
    private static let fullyRedactedKeys: Set<String> = [
        "password", "passwd", "pass", "secret", "token", "access_token",
        "refresh_token", "id_token", "api_key", "apikey", "api_secret",
        "authorization", "auth_token", "session_token", "csrf_token",
        "credit_card", "card_number", "cvv", "cvc", "ssn",
        "social_security", "pin", "private_key", "signing_key",
        "client_secret", "cookie", "set-cookie"
    ]
    
    // Keys whose values should be partially redacted (show partial info)
    private static let partiallyRedactedKeys: Set<String> = [
        "email", "email_address", "phone", "phone_number",
        "address", "street", "ip_address", "ip",
        "date_of_birth", "dob", "name", "full_name",
        "first_name", "last_name"
    ]
    
    /// Redact a single string value based on its key
    static func redact(key: String, value: String) -> String {
        let normalizedKey = key.lowercased().trimmingCharacters(in: .whitespaces)
        
        if fullyRedactedKeys.contains(normalizedKey) {
            return "[REDACTED]"
        }
        
        if partiallyRedactedKeys.contains(normalizedKey) {
            return partialRedact(value: value, key: normalizedKey)
        }
        
        return value
    }
    
    /// Partially redact a value, showing just enough for debugging
    static func partialRedact(value: String, key: String) -> String {
        guard !value.isEmpty else { return "[EMPTY]" }
        
        if key.contains("email") {
            return redactEmail(value)
        }
        
        if key.contains("phone") {
            return redactPhone(value)
        }
        
        if key.contains("ip") {
            return redactIP(value)
        }
        
        // Generic partial redaction: show first 2 and last 1 characters
        return genericPartialRedact(value)
    }
    
    /// Redact email: "user@example.com" -> "u***@e***.com"
    static func redactEmail(_ email: String) -> String {
        let parts = email.split(separator: "@", maxSplits: 1)
        guard parts.count == 2 else { return "[REDACTED_EMAIL]" }
        
        let localPart = String(parts[0])
        let domainPart = String(parts[1])
        
        let redactedLocal = localPart.isEmpty ? "***" : "\(localPart.prefix(1))***"
        
        let domainComponents = domainPart.split(separator: ".")
        let redactedDomain: String
        if domainComponents.count >= 2 {
            let tld = domainComponents.last ?? ""
            redactedDomain = "\(domainComponents.first?.prefix(1) ?? "")***.\(tld)"
        } else {
            redactedDomain = "***"
        }
        
        return "\(redactedLocal)@\(redactedDomain)"
    }
    
    /// Redact phone: "+1234567890" -> "+1***7890"
    static func redactPhone(_ phone: String) -> String {
        let digits = phone.filter { $0.isNumber }
        guard digits.count >= 4 else { return "[REDACTED_PHONE]" }
        let lastFour = digits.suffix(4)
        return "***\(lastFour)"
    }
    
    /// Redact IP: "192.168.1.100" -> "192.168.x.x"
    static func redactIP(_ ip: String) -> String {
        let octets = ip.split(separator: ".")
        guard octets.count == 4 else { return "[REDACTED_IP]" }
        return "\(octets[0]).\(octets[1]).x.x"
    }
    
    /// Generic partial redaction
    static func genericPartialRedact(_ value: String) -> String {
        guard value.count > 4 else { return "[\(value.count) chars REDACTED]" }
        return "\(value.prefix(2))***\(value.suffix(1))"
    }
    
    /// Redact a user ID for logging (show partial)
    static func redactUserID(_ userID: String) -> String {
        guard userID.count > 6 else { return "[\(userID.count) chars]" }
        return "\(userID.prefix(3))...\(userID.suffix(3))"
    }
    
    /// Redact a bearer token or similar credential
    static func redactToken(_ token: String) -> String {
        guard !token.isEmpty else { return "[EMPTY_TOKEN]" }
        return "\(token.prefix(4))...[REDACTED len=\(token.count)]"
    }
    
    /// Recursively redact sensitive keys from a dictionary
    static func redactDictionary(_ dict: [String: Any]) -> [String: Any] {
        var result = [String: Any]()
        for (key, value) in dict {
            let normalizedKey = key.lowercased()
            
            if fullyRedactedKeys.contains(normalizedKey) {
                result[key] = "[REDACTED]"
            } else if partiallyRedactedKeys.contains(normalizedKey) {
                if let stringValue = value as? String {
                    result[key] = partialRedact(value: stringValue, key: normalizedKey)
                } else {
                    result[key] = "[REDACTED_\(type(of: value))]"
                }
            } else if let nestedDict = value as? [String: Any] {
                result[key] = redactDictionary(nestedDict)
            } else if let nestedArray = value as? [[String: Any]] {
                result[key] = nestedArray.map { redactDictionary($0) }
            } else {
                result[key] = value
            }
        }
        return result
    }
    
    /// Redact HTTP headers
    static func redactHeaders(_ headers: [String: String]) -> [String: String] {
        var result = [String: String]()
        for (key, value) in headers {
            let normalizedKey = key.lowercased()
            if fullyRedactedKeys.contains(normalizedKey) || normalizedKey == "authorization" {
                if value.lowercased().hasPrefix("bearer ") {
                    result[key] = "Bearer \(redactToken(String(value.dropFirst(7))))"
                } else {
                    result[key] = "[REDACTED]"
                }
            } else if normalizedKey == "cookie" || normalizedKey == "set-cookie" {
                result[key] = "[REDACTED]"
            } else {
                result[key] = value
            }
        }
        return result
    }
}

// MARK: - Analytics Logger

final class AnalyticsLogger {
    
    static let shared = AnalyticsLogger()
    
    private let environment: BuildEnvironment
    private let minimumLogLevel: LogLevel
    private let logQueue = DispatchQueue(label: "com.app.analytics.logger", qos: .utility)
    private let dateFormatter: DateFormatter
    
    // Configurable maximum payload size for logging (bytes)
    private let maxPayloadLogSize: Int = 1024
    
    private init() {
        self.environment = BuildEnvironment.current
        
        switch environment {
        case .debug:
            self.minimumLogLevel = .verbose
        case .staging:
            self.minimumLogLevel = .info
        case .production:
            self.minimumLogLevel = .warning
        }
        
        self.dateFormatter = DateFormatter()
        self.dateFormatter.dateFormat = "yyyy-MM-dd HH:mm:ss.SSS"
        self.dateFormatter.timeZone = TimeZone(identifier: "UTC")
    }
    
    // MARK: - Core Logging
    
    func log(
        _ level: LogLevel,
        category: LogCategory,
        message: String,
        metadata: [String: Any]? = nil,
        file: String = #file,
        function: String = #function,
        line: Int = #line
    ) {
        guard level >= minimumLogLevel else { return }
        
        logQueue.async { [weak self] in
            guard let self = self else { return }
            
            let timestamp = self.dateFormatter.string(from: Date())
            let fileName = (file as NSString).lastPathComponent
            
            // Redact any sensitive data in metadata
            let safeMetadata: [String: Any]?
            if let metadata = metadata {
                safeMetadata = SensitiveDataRedactor.redactDictionary(metadata)
            } else {
                safeMetadata = nil
            }
            
            var logMessage = "\(timestamp) \(level.prefix) [\(category.rawValue)] \(message)"
            
            // Only include file/function/line in non-production
            if self.environment != .production {
                logMessage += " (\(fileName):\(line) \(function))"
            }
            
            if let safeMetadata = safeMetadata, !safeMetadata.isEmpty {
                if let metadataString = self.formatMetadata(safeMetadata) {
                    logMessage += " | metadata: \(metadataString)"
                }
            }
            
            // In production, use os_log or a secure logging framework
            // For this implementation, we use NSLog only in debug/staging
            switch self.environment {
            case .debug:
                // Full output for local development
                print(logMessage)
            case .staging:
                NSLog("%@", logMessage)
            case .production:
                // In production, only log warnings and above
                // Use a structured logging system, never print/NSLog sensitive data
                if level >= .warning {
                    // Send to secure crash reporting / analytics backend
                    self.sendToSecureBackend(level: level, category: category, message: message, metadata: safeMetadata)
                }
            }
        }
    }
    
    private func formatMetadata(_ metadata: [String: Any]) -> String? {
        guard let data = try? JSONSerialization.data(withJSONObject: metadata, options: []),
              let string = String(data: data, encoding: .utf8) else {
            return nil
        }
        // Truncate if too large
        if string.count > maxPayloadLogSize {
            return String(string.prefix(maxPayloadLogSize)) + "...[TRUNCATED]"
        }
        return string
    }
    
    private func sendToSecureBackend(level: LogLevel, category: LogCategory, message: String, metadata: [String: Any]?) {
        // Integration point for secure analytics backend (e.g., Firebase Crashlytics, Datadog, Sentry)
        // This should use TLS, certificate pinning, and never log raw sensitive data
        // Placeholder implementation:
        let entry = SecureLogEntry(
            timestamp: Date(),
            level: level,
            category: category,
            message: message,
            metadata: metadata
        )
        SecureLogBuffer.shared.enqueue(entry)
    }
}

