}

final class SecureLogBuffer {
    static let shared = SecureLogBuffer()
    
    private var buffer: [SecureLogEntry] = []
    private let bufferQueue = DispatchQueue(label: "com.app.analytics.buffer", qos: .utility)
    private let maxBufferSize = 100
    
    private init() {}
    
    func enqueue(_ entry: SecureLogEntry) {
        bufferQueue.async { [weak self] in
            guard let self = self else { return }
            self.buffer.append(entry)
            if self.buffer.count >= self.maxBufferSize {
                self.flush()
            }
        }
    }
    
    func flush() {
        bufferQueue.async { [weak self] in
            guard let self = self, !self.buffer.isEmpty else { return }
            let entries = self.buffer
            self.buffer.removeAll()
            // Send entries to secure backend over TLS
            // Implementation depends on your analytics provider
            _ = entries // Placeholder: send to backend
        }
    }
}

