final class AuthenticationTracker {
    
    private let logger = AnalyticsLogger.shared
    
    /// Log the start of an authentication attempt
    func trackLoginAttempt(method: AuthMethod, userIdentifierHint: String?) {
        let redactedHint: String
        if let hint = userIdentifierHint {
            if hint.contains("@") {
                redactedHint = SensitiveDataRedactor.redactEmail(hint)
            } else {
                redactedHint = SensitiveDataRedactor.genericPartialRedact(hint)
            }
        } else {
            redactedHint = "none"
        }
        
        logger.log(.info, category: .authentication, message: "Login attempt started", metadata: [
            "method": method.rawValue,
            "identifier_hint": redactedHint
        ])
    }
    
    /// Log successful authentication — NEVER log the actual token
    func trackLoginSuccess(userID: String, method: AuthMethod) {
        logger.log(.info, category: .authentication, message: "Login successful", metadata: [
            "user_id_hint": SensitiveDataRedactor.redactUserID(userID),
            "method": method.rawValue
        ])
    }
    
    /// Log authentication failure with safe error info
    func trackLoginFailure(method: AuthMethod, errorCode: String, errorCategory: AuthErrorCategory) {
        // Log the error code and category, but NOT the raw server response or user credentials
        logger.log(.warning, category: .authentication, message: "Login failed", metadata: [
            "method": method.rawValue,
            "error_code": errorCode,
            "error_category": errorCategory.rawValue
        ])
    }
    
    /// Log token refresh — never log the token itself
    func trackTokenRefresh(success: Bool, userID: String?) {
        let safeUserID = userID.map { SensitiveDataRedactor.redactUserID($0) } ?? "unknown"
        logger.log(
            success ? .info : .warning,
            category: .authentication,
            message: success ? "Token refresh successful" : "Token refresh failed",
            metadata: [
                "user_id_hint": safeUserID
            ]
        )
    }
    
    /// Log logout
    func trackLogout(userID: String?, reason: LogoutReason) {
        let safeUserID = userID.map { SensitiveDataRedactor.redactUserID($0) } ?? "unknown"
        logger.log(.info, category: .authentication, message: "User logged out", metadata: [
            "user_id_hint": safeUserID,
            "reason": reason.rawValue
        ])
