// MARK: - API Call Tracker

final class APICallTracker {
    
    private let logger = AnalyticsLogger.shared
    
    /// Log an outgoing API request — redact sensitive headers and body fields
    func trackRequest(
        requestID: String,
        method: String,
        endpoint: String,
        headers: [String: String]?,
        bodyKeys: [String]?,
        bodySizeBytes: Int?
    ) {
        var metadata: [String: Any] = [
            "request_id": requestID,
            "method": method,
            "endpoint": sanitizeEndpoint(endpoint)
        ]
        
        // Log redacted headers, never raw Authorization values
        if let headers = headers {
            metadata["headers"] = SensitiveDataRedactor.redactHeaders(headers)
        }
        
        // Log only the keys present in the body, NOT the values
        if let bodyKeys = bodyKeys {
            metadata["body_keys"] = bodyKeys
        }
        
        if let size = bodySizeBytes {
            metadata["body_size_bytes"] = size
        }
        
        logger.log(.info, category: .api, message: "API request", metadata: metadata)
    }
    
    /// Log an API response — redact sensitive response fields
    func trackResponse(
        requestID: String,
        endpoint: String,
        statusCode: Int,
        latencyMs: Double,
        responseSizeBytes: Int?,
        responseKeys: [String]?
    ) {
        var metadata: [String: Any] = [
            "request_id": requestID,
            "endpoint": sanitizeEndpoint(endpoint),
            "status_code": statusCode,
            "latency_ms": round(latencyMs * 100) / 100
        ]
        
        if let size = responseSizeBytes {
            metadata["response_size_bytes"] = size
        }
        
        // Log only the top-level keys, NOT the values
        if let keys = responseKeys {
            metadata["response_keys"] = keys
        }
        
        let level: LogLevel = statusCode >= 500 ? .error : (statusCode >= 400 ? .warning : .info)
        
        logger.log(level, category: .api, message: "API response", metadata: metadata)
    }
    
    /// Log an API error — provide diagnostic info without leaking internals
    func trackAPIError(
        requestID: String,
        endpoint: String,
        errorCode: String,
        errorType: APIErrorType,
        isRetryable: Bool
    ) {
        logger.log(.error, category: .api, message: "API error", metadata: [
            "request_id": requestID,
            "endpoint": sanitizeEndpoint(endpoint),
            "error_code": errorCode,
            "error_type": errorType.rawValue,
            "is_retryable": isRetryable
        ])
    }
    
    /// Remove query parameters that might contain tokens or sensitive data from endpoint URLs
    private func sanitizeEndpoint(_ endpoint: String) -> String {
        guard let urlComponents = URLComponents(string: endpoint) else {
            return endpoint
        }
        
        let sensitiveParams: Set<String> = [
            "token", "access_token", "api_key", "key", "secret",
            "password", "auth", "session", "code"
        ]
        
        var sanitized = urlComponents
        if let queryItems = sanitized.queryItems {
            sanitized.queryItems = queryItems.map { item in
                if sensitiveParams.contains(item.name.lowercased()) {
                    return URLQueryItem(name: item.name, value: "[REDACTED]")
                }
                return item
            }
        }
        
        // Also redact path segments that look like UUIDs or IDs (optional, for privacy)
        return sanitized.string ?? endpoint
    }
    
    enum APIErrorType: String {
        case network = "network"
        case timeout = "timeout"
        case serverError = "server_error"
        case clientError = "client_error"
        case parsing = "parsing"
        case cancelled = "cancelled"
        case unauthorized = "unauthorized"
    }
}

