// MARK: - Error Condition Tracker

final class ErrorTracker {
    
    private let logger = AnalyticsLogger.shared
    
    /// Track an application error with safe context
    func trackError(
        errorCode: String,
        errorDomain: String,
        category: ErrorCategory,
        userFacingMessage: String?,
        context: [String: Any]?
    ) {
        // Redact any sensitive data that might be in the context
        let safeContext: [String: Any]?
        if let context = context {
            safeContext = SensitiveDataRedactor.redactDictionary(context)
        } else {
            safeContext = nil
        }
        
        var metadata: [String: Any] = [
            "error_code": errorCode,
            "error_domain": errorDomain,
            "category": category.rawValue
        ]
        
        // Only include user-facing message, never internal error details in production
        if let message = userFacingMessage {
            metadata["user_message"] = message
        }
        
        if let safeContext = safeContext {
            metadata["context"] = safeContext
        }
        
        logger.log(.error, category: .error, message: "Application error", metadata: metadata)
    }
    
    /// Track a caught exception — sanitize the description, never log full stack traces in production
    func trackException(
        _ error: Error,
        context: String,
        isFatal: Bool
    ) {
        let nsError = error as NSError
        
        var metadata: [String: Any] = [
            "error_domain": nsError.domain,
            "error_code": nsError.code,
            "context": context,
            "is_fatal": isFatal
        ]
        
        // In debug, include localized description; in production, use only the code
        #if DEBUG
        metadata["description"] = nsError.localizedDescription
        // In debug only, include a sanitized stack trace hint (not full trace)
        metadata["error_type"] = String(describing: type(of: error))
        #endif
        
        let level: LogLevel = isFatal ? .critical : .error
        logger.log(level, category: .error, message: "Exception caught", metadata: metadata)
    }
    
    /// Track a network connectivity issue
    func trackConnectivityIssue(reachabilityStatus: String, endpoint: String?) {
        var metadata: [String: Any] = [
            "reachability_status": reachabilityStatus
        ]
        if let endpoint = endpoint {
            // Only log the host, not full URL with potential tokens
            if let url = URL(string: endpoint) {
                metadata["host"] = url.host ?? "unknown"
            }
        }
        
        logger.log(.warning, category: .error, message: "Connectivity issue", metadata: metadata)
    }
    
    enum ErrorCategory: String {
        case network = "network"
        case authentication = "authentication"
        case dataCorruption = "data_corruption"
        case storage = "storage"
        case permissions = "permissions"
        case configuration = "configuration"
        case thirdParty = "third_party"
        case unknown = "unknown"
    }
}

