final class PerformanceTracker {
    
    private let logger = AnalyticsLogger.shared
    
    /// Track app launch time
    func trackAppLaunch(coldStart: Bool, durationMs: Double) {
        logger.log(.info, category: .performance, message: "App launched", metadata: [
            "cold_start": coldStart,
            "duration_ms": round(durationMs * 100) / 100
        ])
    }
    
    /// Track a timed operation
    func trackOperation(name: String, durationMs: Double, success: Bool) {
        let level: LogLevel = durationMs > 5000 ? .warning : .info
        
        logger.log(level, category: .performance, message: "Operation completed", metadata: [
            "operation": name,
            "duration_ms": round(durationMs * 100) / 100,
            "success": success
        ])
    }
    
    /// Track memory warnings
    func trackMemoryWarning(usedMemoryMB: Double?) {
        var metadata: [String: Any] = [:]
        if let memory = usedMemoryMB {
            metadata["used_memory_mb"] = round(memory * 100) / 100
        }
        
        logger.log(.warning, category: .performance, message: "Memory warning received", metadata: metadata)
    }
}

// MARK: - App Lifecycle Tracker

final class LifecycleTracker {
    
    private let logger = AnalyticsLogger.shared
    
    func trackAppDidBecomeActive() {
        logger.log(.info, category: .lifecycle, message: "App became active")
    }
    
    func trackAppDidEnterBackground() {
        logger.log(.info, category: .lifecycle, message: "App entered background")
    }
    
    func trackAppWillTerminate() {
        logger.log(.info, category: .lifecycle, message: "App will terminate")
        SecureLogBuffer.shared.flush()
    }
}

// MARK: - Convenience Facade

final class AppAnalytics {
    
    static let shared = AppAnalytics()
    
    let auth = AuthenticationTracker()
    let api = APICallTracker()
    let userData = UserDataTracker()
    let errors = ErrorTracker()
    let interactions = InteractionTracker()
    let performance = PerformanceTracker()
    let lifecycle = LifecycleTracker()
    
    private init() {}
    
    /// Flush any buffered logs (call on app termination or backgrounding)
    func flush() {
        SecureLogBuffer.shared.flush()
    }
}

